//! Spec-compliance edge cases: Table Structure & Borders
//!
//! These tests target behavioral edge cases in OOXML table handling where
//! parsers commonly misinterpret the spec.
//!
//! Fixture DOCX files are generated by `testdata/spec-compliance/create_docs.py`.

use stemma::{BlockNode, CanonDoc, DocxRuntime, InlineNode, TableNode};

use crate::common;

const FIXTURES: &str = "testdata/spec-compliance/edge-cases";

// ── helpers ──────────────────────────────────────────────────────────────
fn first_table(doc: &CanonDoc) -> &TableNode {
    doc.blocks
        .iter()
        .find_map(|b| match &b.block {
            BlockNode::Table(t) => Some(t.as_ref()),
            _ => None,
        })
        .expect("document should contain at least one table")
}

/// Collect all tables from the document body in order.
fn all_tables(doc: &CanonDoc) -> Vec<&TableNode> {
    doc.blocks
        .iter()
        .filter_map(|b| match &b.block {
            BlockNode::Table(t) => Some(t.as_ref()),
            _ => None,
        })
        .collect()
}

fn cell_text(table: &TableNode, row: usize, col: usize) -> String {
    let cell = &table.rows[row].cells[col];
    let mut text = String::new();
    for block in &cell.blocks {
        if let BlockNode::Paragraph(p) = block {
            let inlines = p.all_inlines_owned();
            for inline in &inlines {
                if let InlineNode::Text(t) = inline {
                    text.push_str(&t.text);
                }
            }
        }
    }
    text
}

// ── EC-14: Table border conflict resolution ─────────────────────────────

/// ISO 29500-1 §17.4.38: Cell-level borders override table-level borders.
///
/// Fixture has thick red (sz=24) table-level borders on all edges.
/// Cell (0,0) overrides with thin blue (sz=4) cell-level borders.
#[test]
fn ec14_border_conflict_parses_without_error() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "border-conflict");
    let table = first_table(&doc);
    assert_eq!(table.rows.len(), 2, "should have 2 rows");
    assert_eq!(table.rows[0].cells.len(), 2, "should have 2 cells per row");
}

/// Table-level borders should be present on the table formatting.
#[test]
fn ec14_table_level_borders_are_present() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "border-conflict");
    let table = first_table(&doc);

    let borders = table
        .formatting
        .borders
        .as_ref()
        .expect("table should have table-level borders");

    // All table-level borders should be red/sz=24
    for (name, edge) in [
        ("top", &borders.top),
        ("bottom", &borders.bottom),
        ("left", &borders.left),
        ("right", &borders.right),
        ("insideH", &borders.inside_h),
        ("insideV", &borders.inside_v),
    ] {
        let border = edge
            .as_ref()
            .unwrap_or_else(|| panic!("table border edge '{name}' should be present"));
        assert_eq!(
            border.style,
            stemma::domain::BorderStyle::Single,
            "table {name} border style"
        );
        assert_eq!(
            border.size,
            Some(24),
            "table {name} border size should be 24 (3pt)"
        );
        assert_eq!(
            border.color.as_deref(),
            Some("FF0000"),
            "table {name} border color should be red"
        );
    }
}

/// MS-OI29500 §2.1.169: Cell border vs table border weight resolution.
///
/// Cell (0,0) has explicit tcBorders (blue/sz=4, weight=4). Table has
/// direct tblBorders (red/sz=24, weight=24). Per MS implementation,
/// weight-based resolution applies to all edges (including table edges).
/// The heavier table border (weight=24) wins over the lighter cell border
/// (weight=4) on every edge.
#[test]
fn ec14_cell_borders_override_table_borders() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "border-conflict");
    let table = first_table(&doc);

    let cell_00 = &table.rows[0].cells[0];
    let cell_borders = cell_00
        .formatting
        .borders
        .as_ref()
        .expect("cell (0,0) should have borders after conflict resolution");

    // MS-OI29500 §2.1.169: table border (red/24, weight=24) wins over cell
    // border (blue/4, weight=4) on ALL edges (weight-based resolution).
    for (name, edge) in [
        ("top", &cell_borders.top),
        ("bottom", &cell_borders.bottom),
        ("left", &cell_borders.left),
        ("right", &cell_borders.right),
    ] {
        let border = edge
            .as_ref()
            .unwrap_or_else(|| panic!("cell border edge '{name}' should be present"));
        assert_eq!(
            border.style,
            stemma::domain::BorderStyle::Single,
            "cell {name} border style"
        );
        assert_eq!(
            border.size,
            Some(24),
            "cell {name} border should be sz=24 — table red (weight=24) beats cell blue (weight=4)"
        );
        assert_eq!(
            border.color.as_deref(),
            Some("FF0000"),
            "cell {name} border should be red (table wins by weight)"
        );
    }
}

/// Cell (0,1) has no explicit tcBorders in XML, but after table-level border
/// cascade and adjacent cell conflict resolution (§17.4.66 rule 3), it gets
/// borders: table fallback on non-shared edges, and the winner from cell (0,0)
/// on the shared left edge.
#[test]
fn ec14_cell_without_tcborders_gets_cascade_and_conflict_borders() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "border-conflict");
    let table = first_table(&doc);

    let cell_01 = &table.rows[0].cells[1];
    // After cascade + conflict resolution, cell (0,1) should have borders.
    let borders = cell_01
        .formatting
        .borders
        .as_ref()
        .expect("cell (0,1) should have borders after table cascade + conflict resolution");
    // Cell (0,1) gets table-level red/sz=24 borders from cascade.
    // At the shared left edge: cell (0,0) has blue/sz=4 (weight=4),
    // cell (0,1) has red/sz=24 (weight=24) from table cascade.
    // Red wins because 24 > 4.
    let left = borders
        .left
        .as_ref()
        .expect("cell (0,1) left border should exist from table cascade");
    assert_eq!(
        left.color.as_deref(),
        Some("FF0000"),
        "cell (0,1) left border should be red (table-level sz=24 beats cell (0,0) blue sz=4)"
    );
}

// ── EC-16: gridSpan="1" vs absent gridSpan ──────────────────────────────

/// ISO 29500-1 §17.4.17: explicit gridSpan="1" is equivalent to absent gridSpan.
#[test]
fn ec16_gridspan_explicit_vs_absent_parses() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "gridspan-explicit-vs-absent");
    let tables = all_tables(&doc);
    assert!(
        tables.len() >= 2,
        "should have at least 2 tables, got {}",
        tables.len()
    );
}

/// Both tables should produce grid_span=1 on every cell.
#[test]
fn ec16_both_tables_have_gridspan_1() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "gridspan-explicit-vs-absent");
    let tables = all_tables(&doc);

    let tbl_no_gridspan = tables[0];
    let tbl_explicit_gridspan = tables[1];

    // Table 1 (no gridSpan): every cell should have grid_span=1
    for (r, row) in tbl_no_gridspan.rows.iter().enumerate() {
        for (c, cell) in row.cells.iter().enumerate() {
            assert_eq!(
                cell.grid_span, 1,
                "table 1 cell ({r},{c}) grid_span should be 1 (default)"
            );
        }
    }

    // Table 2 (explicit gridSpan="1"): every cell should also have grid_span=1
    for (r, row) in tbl_explicit_gridspan.rows.iter().enumerate() {
        for (c, cell) in row.cells.iter().enumerate() {
            assert_eq!(
                cell.grid_span, 1,
                "table 2 cell ({r},{c}) grid_span should be 1 (explicit)"
            );
        }
    }
}

/// Both tables should have identical structure (same row/cell counts).
#[test]
fn ec16_both_tables_have_identical_structure() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "gridspan-explicit-vs-absent");
    let tables = all_tables(&doc);

    let tbl1 = tables[0];
    let tbl2 = tables[1];

    assert_eq!(
        tbl1.rows.len(),
        tbl2.rows.len(),
        "both tables should have the same number of rows"
    );

    for (r, (row1, row2)) in tbl1.rows.iter().zip(tbl2.rows.iter()).enumerate() {
        assert_eq!(
            row1.cells.len(),
            row2.cells.len(),
            "row {r}: both tables should have the same number of cells"
        );
    }
}

// ── EC-17: Empty table cells are rejected ───────────────────────────────

/// ISO 29500-1 §17.4.73 CT_Tc requires `(p|tbl)+` — a cell with zero
/// block-level children is invalid OOXML and must be rejected at import.
#[test]
fn ec17_empty_cell_rejected_on_import() {
    let path = format!("{FIXTURES}/empty-table-cells/input.docx");
    let bytes = std::fs::read(&path).unwrap_or_else(|e| panic!("read {path}: {e}"));
    let runtime = stemma::SimpleRuntime::new();
    let err = runtime
        .import_docx(&bytes)
        .expect_err("import should reject a cell with no block elements");
    let msg = format!("{err:?}");
    assert!(
        msg.contains("must contain at least one block element"),
        "error should cite the CT_Tc content-model violation, got: {msg}"
    );
}

