/// The nested table cells should contain the correct text.
#[test]
fn ec20_nested_table_content() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "nested-table");
    let outer = first_table(&doc);

    let cell_00 = &outer.rows[0].cells[0];
    let nested = cell_00
        .blocks
        .iter()
        .find_map(|b| match b {
            BlockNode::Table(t) => Some(t.as_ref()),
            _ => None,
        })
        .expect("cell (0,0) should contain a nested table");

    // Read text from nested table cells
    let nested_r0_text = cell_text(nested, 0, 0);
    assert!(
        nested_r0_text.contains("Nested R1"),
        "nested table row 0 should contain 'Nested R1', got: '{nested_r0_text}'"
    );

    let nested_r1_text = cell_text(nested, 1, 0);
    assert!(
        nested_r1_text.contains("Nested R2"),
        "nested table row 1 should contain 'Nested R2', got: '{nested_r1_text}'"
    );
}

/// Cell (0,0) should also contain paragraphs alongside the nested table.
#[test]
fn ec20_cell_has_paragraphs_around_nested_table() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "nested-table");
    let outer = first_table(&doc);

    let cell_00 = &outer.rows[0].cells[0];

    let paragraph_count = cell_00
        .blocks
        .iter()
        .filter(|b| matches!(b, BlockNode::Paragraph(_)))
        .count();

    // Should have at least the "Before nested" paragraph and the trailing empty one
    assert!(
        paragraph_count >= 1,
        "cell (0,0) should have at least 1 paragraph alongside the nested table, got {paragraph_count}"
    );

    // The "Before nested" paragraph text
    let first_para_text: String = cell_00
        .blocks
        .iter()
        .find_map(|b| match b {
            BlockNode::Paragraph(p) => {
                let inlines = p.all_inlines_owned();
                let text: String = inlines
                    .iter()
                    .filter_map(|i| match i {
                        InlineNode::Text(t) => Some(t.text.as_str()),
                        _ => None,
                    })
                    .collect();
                if !text.is_empty() { Some(text) } else { None }
            }
            _ => None,
        })
        .unwrap_or_default();

    assert!(
        first_para_text.contains("Before nested"),
        "first paragraph in cell (0,0) should contain 'Before nested', got: '{first_para_text}'"
    );
}

// ── EC-21: Empty table (zero rows) is accepted and preserved ────────────

// An earlier revision of this test asserted REJECTION, reading the §17.4.37
// prose ("an arbitrary non-zero number of rows") as normative over the
// schema. That expectation was wrong: the transitional XSD's CT_Tbl puts the
// row group (EG_ContentRowContent) at minOccurs="0", so tblPr + tblGrid with
// zero w:tr children is schema-valid; wild Word-authored documents contain
// such tables and Word opens them without repair. The schema and Word agree
// — a conforming consumer must accept and preserve the table, not refuse
// the document.

/// Import a document containing a zero-row table (tblPr + tblGrid only):
/// the import succeeds and the canonical model carries the table as a
/// TableNode with empty rows, its width and grid intact.
#[test]
fn ec21_empty_table_zero_rows_imports() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "empty-table-zero-rows");
    let table = first_table(&doc);
    assert!(
        table.rows.is_empty(),
        "the zero-row table must import with empty rows, got {} rows",
        table.rows.len()
    );
    assert_eq!(
        table.formatting.grid_cols,
        vec![4680, 4680],
        "tblGrid must be preserved on the empty table"
    );
    let width = table
        .formatting
        .width
        .as_ref()
        .expect("tblW must be preserved on the empty table");
    assert_eq!(width.w, 5000);
    assert_eq!(width.width_type, stemma::WidthType::Pct);
    // The surrounding paragraphs are intact.
    let texts: Vec<String> = common::all_paragraphs(&doc)
        .iter()
        .map(|p| paragraph_text(p))
        .collect();
    assert!(texts.iter().any(|t| t.contains("Before the empty table")));
    assert!(texts.iter().any(|t| t.contains("After the empty table")));
}

/// Roundtrip: import → export → reimport. The empty table (tblPr + tblGrid,
/// zero rows) and the surrounding text survive both directions.
#[test]
fn ec21_empty_table_zero_rows_roundtrips() {
    use stemma::api::Document;
    let path = format!("{FIXTURES}/empty-table-zero-rows/input.docx");
    let bytes = std::fs::read(&path).unwrap_or_else(|e| panic!("read {path}: {e}"));

    let doc = Document::parse(&bytes).expect("parse doc with zero-row table");
    let exported = doc
        .serialize(&stemma::ExportOptions::default())
        .expect("serialize doc with zero-row table");

    // The re-emitted document must still parse (Word-openable output is
    // gated elsewhere; reparse is the in-repo proxy) and still contain the
    // empty table with its grid and the surrounding text.
    let (_runtime2, doc2) = {
        let runtime = stemma::SimpleRuntime::new();
        let import = runtime.import_docx(&exported).expect("reimport export");
        let view = runtime.view(&import.doc_handle).expect("view");
        let canon = std::sync::Arc::unwrap_or_clone(view.canonical);
        (runtime, canon)
    };
    let table = first_table(&doc2);
    assert!(
        table.rows.is_empty(),
        "empty table must survive the roundtrip with zero rows"
    );
    assert_eq!(
        table.formatting.grid_cols,
        vec![4680, 4680],
        "tblGrid must survive the roundtrip"
    );
    let texts: Vec<String> = common::all_paragraphs(&doc2)
        .iter()
        .map(|p| paragraph_text(p))
        .collect();
    assert!(texts.iter().any(|t| t.contains("Before the empty table")));
    assert!(texts.iter().any(|t| t.contains("After the empty table")));
}

/// Redline path: edit a DIFFERENT paragraph via diff_and_redline and export.
/// The untouched empty table must survive the tracked-changes export and the
/// reparse of its output.
#[test]
fn ec21_empty_table_zero_rows_survives_redline() {
    use stemma::{DocxRuntime, ExportMode, SimpleRuntime, TransactionMeta};
    let path = format!("{FIXTURES}/empty-table-zero-rows/input.docx");
    let bytes = std::fs::read(&path).unwrap_or_else(|e| panic!("read {path}: {e}"));
    let edited_bytes = rezip_with_patched_document_xml(
        &bytes,
        "After the empty table.",
        "After the empty table, now edited.",
    );

    let runtime = SimpleRuntime::new();
    let base = runtime.import_docx(&bytes).expect("import base");
    let edited = runtime.import_docx(&edited_bytes).expect("import edited");
    let meta = TransactionMeta {
        author: "spec_edge_tables".to_string(),
        reason: Some("zero-row table redline survival".to_string()),
        timestamp_utc: Some("2025-01-15T10:30:00Z".to_string()),
    };
    let apply = runtime
        .diff_and_redline(&base.doc_handle, &edited.doc_handle, meta)
        .expect("diff_and_redline");
    assert!(apply.applied, "redline should be applied");
    let redline = runtime
        .export_docx(&base.doc_handle, ExportMode::Redline)
        .expect("export redline");

    // Reparse the redline output: the empty table is still there, untouched,
    // and the paragraph edit is present.
    let runtime2 = SimpleRuntime::new();
    let import2 = runtime2.import_docx(&redline).expect("reimport redline");
    let view = runtime2.view(&import2.doc_handle).expect("view");
    let doc2 = std::sync::Arc::unwrap_or_clone(view.canonical);
    let table = first_table(&doc2);
    assert!(
        table.rows.is_empty(),
        "empty table must survive the redline export with zero rows"
    );
    assert_eq!(
        table.formatting.grid_cols,
        vec![4680, 4680],
        "tblGrid must survive the redline export"
    );
    let texts: Vec<String> = common::all_paragraphs(&doc2)
        .iter()
        .map(|p| paragraph_text(p))
        .collect();
    assert!(
        texts.iter().any(|t| t.contains("now edited")),
        "the paragraph edit must be present in the redline output, got: {texts:?}"
    );
}

/// Extract text from a paragraph node (test-local convenience).
fn paragraph_text(p: &stemma::ParagraphNode) -> String {
    p.all_inlines_owned()
        .iter()
        .filter_map(|i| match i {
            InlineNode::Text(t) => Some(t.text.clone()),
            _ => None,
        })
        .collect()
}

/// Rebuild a DOCX byte-for-byte, replacing `from` with `to` inside
/// word/document.xml (test-local; used to author the "edited elsewhere"
/// counterpart of a fixture).
fn rezip_with_patched_document_xml(docx: &[u8], from: &str, to: &str) -> Vec<u8> {
    use std::io::{Cursor, Read, Write};
    let mut zip = zip::ZipArchive::new(Cursor::new(docx)).expect("open fixture zip");
    let mut out = Vec::new();
    {
        let mut writer = zip::ZipWriter::new(Cursor::new(&mut out));
        for i in 0..zip.len() {
            let mut entry = zip.by_index(i).expect("zip entry");
            let name = entry.name().to_string();
            let mut contents = Vec::new();
            entry.read_to_end(&mut contents).expect("read zip entry");
            if name == "word/document.xml" {
                let xml = String::from_utf8(contents).expect("document.xml utf8");
                assert!(
                    xml.contains(from),
                    "patch target '{from}' not found in fixture document.xml"
                );
                contents = xml.replace(from, to).into_bytes();
            }
            writer
                .start_file(name, zip::write::FileOptions::default())
                .expect("start zip entry");
            writer.write_all(&contents).expect("write zip entry");
        }
        writer.finish().expect("finish zip");
    }
    out
}

/// Outer table's other cells should have their expected content.
#[test]
fn ec20_outer_table_other_cells() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "nested-table");
    let outer = first_table(&doc);

    let b1 = cell_text(outer, 0, 1);
    assert!(
        b1.contains("Outer B1"),
        "outer cell (0,1) should contain 'Outer B1', got: '{b1}'"
    );

    let a2 = cell_text(outer, 1, 0);
    assert!(
        a2.contains("Outer A2"),
        "outer cell (1,0) should contain 'Outer A2', got: '{a2}'"
    );

    let b2 = cell_text(outer, 1, 1);
    assert!(
        b2.contains("Outer B2"),
        "outer cell (1,1) should contain 'Outer B2', got: '{b2}'"
    );
}
